### ✅ Option 1: Web-Based 3D House (HTML + Three.js)

This interactive scene renders a simple block-style house using Three.js. You can save and open this file in any modern web browser.

**Instructions:**
1. Save the code below as `house.html`.
2. Open it in your browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8" />
    <title>3D House</title>
    <style>
        body { margin: 0; overflow: hidden; }
        canvas { display: block; }
    </style>
</head>
<body>
    <!-- Load Three.js -->
    <script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
    <script>
        const scene = new THREE.Scene();
        const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);
        const dirLight = new THREE.DirectionalLight(0xffffff, 0.9);
        dirLight.position.set(5, 10, 7);
        dirLight.castShadow = true;
        scene.add(dirLight);

        // Materials
        const wallMaterial = new THREE.MeshPhongMaterial({ color: 0xaaaaaa });
        const roofMaterial = new THREE.MeshPhongMaterial({ color: 0xcc3300 });
        const floorMaterial = new THREE.MeshStandardMaterial({ map: null, roughness: 0.8 });

        // Functions to build geometry
        function addWall(x, y, z, w, h, d, material) {
            const geo = new THREE.BoxGeometry(w, h, d);
            const mesh = new THREE.Mesh(geo, material);
            mesh.position.set(x, y, z);
            mesh.castShadow = true;
            scene.add(mesh);
            return mesh;
        }

        function addFloor(size) {
            const geo = new THREE.PlaneGeometry(size, size);
            const mesh = new THREE.Mesh(geo, floorMaterial);
            mesh.rotation.x = -Math.PI / 2;
            mesh.receiveShadow = true;
            scene.add(mesh);
        }

        function addRoof(width, depth) {
            const geo = new THREE.ConeGeometry(Math.sqrt(width * width + depth * depth), 3, 4);
            const mat = new THREE.MeshToonMaterial({ color: 0xcc3300 });
            const mesh = new THREE.Mesh(geo, mat);
            mesh.position.y = 2.5;
            mesh.rotation.y = Math.PI / 4;
            mesh.scale.z = -mesh.scale.z;
            scene.add(mesh);
        }

        // Build the house
        const houseWidth = 6;
        const houseDepth = 4;
        const houseHeight = 3;

        addFloor(houseWidth * 2, houseDepth * 2);

        // Walls
        addWall(0, 1.5, householdDepth/2, houseWidth, houseHeight, houseDepth, wallMaterial);
        addWall(houseDepth/2, 1.5, 0, houseDepth, houseHeight, houseWidth, wallMaterial);
        addWall(-houseWidth/2, 1.5, householdDepth/2, houseWidth, houseHeight, houseDepth, wallMaterial);
        addWall(houseDepth/2, 1.5, 0, houseDepth, houseHeight, houseWidth, wallMaterial);

        // Roof
        addRoof(houseWidth * 2, houseDepth * 2);

        // Camera setup
        camera.position.z = 14;
        camera.position.y = 6;
        camera.lookAt(0, 2, 0);

        // Animation loop
        function animate() {
            requestAnimationFrame(animate);
            renderer.render(scene, camera);
        }
        animate();

        // Handle window resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });
    </script>
</body>
</html>
```

💡 Note: There appears to be a small issue in the original sample—`householdDepth/2` is not a valid variable name. Here’s the fixed version inside the script:

```javascript
addWall(0, 1.5, houseDepth/2, houseWidth, houseHeight, houseDepth, wallMaterial);
```

